  "INDOOR-NOISE": {
   "name": "INDOOR-NOISE",
   "kind": "global",
   "file": "parlor.zil",
   "line": 1030,
   "value": "<LTABLE 0 \"Somewhere in the house you hear the thud of something falling on the floor.\" ;\"Nearby you hear the scraping noise of something being dragged across the floor.\" ;\"Without warning, a door slams shut.\" \"You hear the eerie whistling of wind coming down the chimney.\" \"Somewhere in the house you hear the creaking of floorboards.\" ;\"Suddenly the antique music box begins to play an old melody.\" ;\"There is a faint tapping on the window.\" ;\"Suddenly, maniacal laughter fills the house.\">"
  },
  "OUTDOOR-NOISE": {
   "name": "OUTDOOR-NOISE",
   "kind": "global",
   "file": "parlor.zil",
   "line": 1041,
   "value": "<LTABLE 0 ;\"You hear the thunder of waves crashing on the rocks.\" \"You can hear dogs howling in the distance.\" ;\"All around the house you can hear the shrieking of seagulls.\" ;\"In the distance you hear the ominous rumbling of thunder.\" ;\"Suddenly overhead there is a loud bang of thunder.\" \"Somewhere nearby several of Morgan Fairchild's cats begin crying.\" ;\"You can hear somewhere a door banging against the house.\" \"From the ocean there is the distant ringing of warning buoys.\" ;\"The foghorn begins warning any boats still in the area.\" \"Shadows pour over you as grey clouds sweep past the night's full moon.\">"
  },
